const { defineConfig } = require('cypress');

module.exports = defineConfig({
  e2e: {
    setupNodeEvents(on, config) {
      // implement node event listeners here
    },
    baseUrl: 'http://localhost:8080',
    supportFile: false,
    specPattern: 'cypress/e2e/**/*.cy.js',
  },
  component: {
    devServer: {
      framework: 'express',
      bundler: 'webpack',
    },
  },
});

/* ============================================
   MediCap — Main Application Controller
   ============================================ */

const App = {
    // Current booking context
    _bookingDoctorId: null,
    _filterDebounce: null,

    // Initialize application
    init() {
        Store.init();
        Store.updateThemeIcon();
        Store.updateAuthUI();
        this.bindNavigation();
        this.bindTheme();
        this.bindMobileNav();
        this.bindScroll();
        this.renderPage('home');
        this.hidePreloader();
    },

    // Hide preloader after load
    hidePreloader() {
        setTimeout(() => {
            const preloader = document.getElementById('preloader');
            if (preloader) preloader.classList.add('hidden');
        }, 800);
    },

    // ========== NAVIGATION ==========
    bindNavigation() {
        // Desktop nav links
        document.querySelectorAll('[data-page]').forEach(link => {
            link.addEventListener('click', (e) => {
                e.preventDefault();
                const page = link.getAttribute('data-page');
                this.navigateTo(page);
            });
        });

        // User dropdown toggle
        const avatarBtn = document.getElementById('user-avatar-btn');
        const dropdown = document.getElementById('user-dropdown');
        if (avatarBtn && dropdown) {
            avatarBtn.addEventListener('click', () => {
                dropdown.classList.toggle('hidden');
            });
            document.addEventListener('click', (e) => {
                if (!avatarBtn.contains(e.target) && !dropdown.contains(e.target)) {
                    dropdown.classList.add('hidden');
                }
            });
        }

        // Logout
        const logoutBtn = document.getElementById('logout-btn');
        if (logoutBtn) {
            logoutBtn.addEventListener('click', (e) => {
                e.preventDefault();
                this.handleLogout();
            });
        }
    },

    bindTheme() {
        const themeBtn = document.getElementById('theme-toggle');
        if (themeBtn) {
            themeBtn.addEventListener('click', () => Store.toggleTheme());
        }
    },

    bindMobileNav() {
        const hamburger = document.getElementById('hamburger');
        const mobileNav = document.getElementById('mobile-nav');
        const mobileOverlay = document.getElementById('mobile-overlay');
        const mobileClose = document.getElementById('mobile-close');

        const openMobile = () => {
            mobileNav.classList.remove('hidden');
            mobileOverlay.classList.remove('hidden');
            document.body.style.overflow = 'hidden';
        };

        const closeMobile = () => {
            mobileNav.classList.add('hidden');
            mobileOverlay.classList.add('hidden');
            document.body.style.overflow = '';
        };

        hamburger?.addEventListener('click', openMobile);
        mobileClose?.addEventListener('click', closeMobile);
        mobileOverlay?.addEventListener('click', closeMobile);

        // Mobile nav links
        document.querySelectorAll('.mobile-link, #mobile-login-btn').forEach(link => {
            link.addEventListener('click', (e) => {
                e.preventDefault();
                const page = link.getAttribute('data-page');
                closeMobile();
                this.navigateTo(page);
            });
        });
    },

    bindScroll() {
        let lastScroll = 0;
        window.addEventListener('scroll', () => {
            const nav = document.getElementById('main-nav');
            if (window.scrollY > 50) {
                nav.classList.add('scrolled');
            } else {
                nav.classList.remove('scrolled');
            }
            lastScroll = window.scrollY;
        });
    },

    navigateTo(page, doctorId = null, city = null) {
        // Update active nav link
        document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active'));
        document.querySelectorAll('.mobile-link').forEach(l => l.classList.remove('active'));

        const navPage = page === 'book-appointment' ? 'appointments' : page;
        document.querySelectorAll(`[data-page="${navPage}"]`).forEach(l => l.classList.add('active'));

        // Close dropdown
        const dropdown = document.getElementById('user-dropdown');
        if (dropdown) dropdown.classList.add('hidden');

        // Render page
        if (page === 'book-appointment' && doctorId) {
            this._bookingDoctorId = doctorId;
            this.renderPage('book-appointment', doctorId);
        } else if (page === 'doctors' && city) {
            Store.state.filters.city = city;
            this.renderPage('doctors');
        } else {
            Store.state.filters = { specialty: 'All', city: 'All', search: '' };
            this.renderPage(page);
        }

        Store.setPage(page);
    },

    renderPage(page, arg = null) {
        const content = document.getElementById('app-content');
        const footer = document.getElementById('main-footer');

        // Show/hide footer for auth pages
        if (page === 'login' || page === 'register') {
            footer.style.display = 'none';
        } else {
            footer.style.display = '';
        }

        switch (page) {
            case 'home':
                content.innerHTML = Pages.home();
                break;
            case 'doctors':
                content.innerHTML = Pages.doctors(Store.state.filters);
                break;
            case 'appointments':
                content.innerHTML = Pages.appointments();
                break;
            case 'book-appointment':
                content.innerHTML = Pages.bookAppointment(arg);
                this.bindBookingDateListener();
                break;
            case 'records':
                content.innerHTML = Pages.records();
                break;
            case 'dashboard':
                content.innerHTML = Pages.dashboard();
                break;
            case 'login':
                content.innerHTML = Pages.login();
                break;
            case 'register':
                content.innerHTML = Pages.register();
                break;
            case 'profile':
                content.innerHTML = Pages.profile();
                break;
            default:
                content.innerHTML = Pages.home();
        }

        // Trigger animations
        this.triggerAnimations();
    },

    triggerAnimations() {
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.style.animationPlayState = 'running';
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.1 });

        document.querySelectorAll('.fade-in, .slide-up, .scale-in').forEach(el => {
            observer.observe(el);
        });
    },

    // ========== DOCTOR FILTERS ==========
    filterDoctors(type, value) {
        Store.state.filters[type] = value;

        if (type === 'search') {
            clearTimeout(this._filterDebounce);
            this._filterDebounce = setTimeout(() => {
                this.renderPage('doctors');
            }, 300);
        } else {
            this.renderPage('doctors');
        }
    },

    // ========== APPOINTMENT MANAGEMENT ==========
    switchAppointmentTab(tab, btn) {
        document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
        btn.classList.add('active');

        document.getElementById('appointments-upcoming').classList.toggle('hidden', tab !== 'upcoming');
        document.getElementById('appointments-past').classList.toggle('hidden', tab !== 'past');
    },

    cancelAppointment(id) {
        Components.showModal(
            'Cancel Appointment',
            `<p style="color:var(--text-secondary); margin-bottom:var(--space-4);">Are you sure you want to cancel this appointment? This action cannot be undone.</p>`,
            `<button class="btn btn-secondary" onclick="Components.closeModal()" id="cancel-modal-no">Keep Appointment</button>
             <button class="btn btn-danger" onclick="App.confirmCancel('${id}')" id="cancel-modal-yes">Yes, Cancel</button>`
        );
    },

    confirmCancel(id) {
        Store.cancelAppointment(id);
        Components.closeModal();
        this.renderPage('appointments');
        Components.showToast('success', 'Cancelled', 'Your appointment has been cancelled.');
    },

    rescheduleAppointment(id) {
        Components.showToast('info', 'Reschedule', 'Please cancel and rebook to reschedule your appointment.');
    },

    // ========== BOOKING ==========
    selectTimeSlot(element, time) {
        if (element.classList.contains('unavailable')) return;

        document.querySelectorAll('.time-slot').forEach(s => s.classList.remove('selected'));
        element.classList.add('selected');
        document.getElementById('booking-time').value = time;

        const summaryTime = document.getElementById('summary-time');
        if (summaryTime) summaryTime.textContent = time;
    },

    bindBookingDateListener() {
        const dateInput = document.getElementById('booking-date');
        if (dateInput) {
            dateInput.addEventListener('change', (e) => {
                const summaryDate = document.getElementById('summary-date');
                if (summaryDate && e.target.value) {
                    const date = new Date(e.target.value);
                    summaryDate.textContent = date.toLocaleDateString('en-IN', {
                        day: 'numeric', month: 'short', year: 'numeric'
                    });
                }
            });
        }
    },

    submitBooking(e) {
        e.preventDefault();

        const name = document.getElementById('booking-name').value;
        const phone = document.getElementById('booking-phone').value;
        const date = document.getElementById('booking-date').value;
        const time = document.getElementById('booking-time').value;
        const type = document.getElementById('booking-type').value;
        const notes = document.getElementById('booking-notes').value;
        const doctorId = document.getElementById('booking-doctor-id').value;

        if (!time) {
            Components.showToast('error', 'Time Required', 'Please select a time slot for your appointment.');
            return;
        }

        if (!date) {
            Components.showToast('error', 'Date Required', 'Please select a date for your appointment.');
            return;
        }

        const appointment = {
            doctorId,
            patientName: name,
            date,
            time,
            type,
            status: 'confirmed',
            notes
        };

        Store.addAppointment(appointment);
        Components.showToast('success', 'Booked!', `Your appointment has been confirmed for ${date} at ${time}.`);

        setTimeout(() => {
            this.navigateTo('appointments');
        }, 1500);
    },

    // ========== AUTH ==========
    handleLogin(e) {
        e.preventDefault();
        const email = document.getElementById('login-email').value;
        const password = document.getElementById('login-password').value;

        if (!email || !password) {
            Components.showToast('error', 'Error', 'Please fill in all fields.');
            return;
        }

        // Simulate login
        const userData = {
            name: email.split('@')[0].replace(/\./g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
            email,
            role: 'patient',
            city: 'Ahmedabad',
            phone: '+91 98765 43210'
        };

        Store.login(userData);
        Components.showToast('success', 'Welcome!', `Logged in as ${userData.name}`);

        setTimeout(() => {
            this.navigateTo('dashboard');
        }, 1000);
    },

    handleRegister(e) {
        e.preventDefault();
        const name = document.getElementById('register-name').value;
        const email = document.getElementById('register-email').value;
        const phone = document.getElementById('register-phone').value;
        const city = document.getElementById('register-city').value;
        const role = document.getElementById('register-role').value;
        const password = document.getElementById('register-password').value;

        if (!name || !email || !phone || !city || !password) {
            Components.showToast('error', 'Error', 'Please fill in all required fields.');
            return;
        }

        const userData = { name, email, phone, city, role };
        Store.login(userData);
        Components.showToast('success', 'Account Created!', `Welcome to MediCap, ${name}!`);

        setTimeout(() => {
            this.navigateTo('dashboard');
        }, 1000);
    },

    selectRole(element, role) {
        document.querySelectorAll('.role-option').forEach(r => r.classList.remove('selected'));
        element.classList.add('selected');
        document.getElementById('register-role').value = role;
    },

    handleLogout() {
        Store.logout();
        Components.showToast('info', 'Logged Out', 'You have been signed out successfully.');
        this.navigateTo('home');
    },

    // ========== PROFILE ==========
    editProfile() {
        const nameInput = document.getElementById('profile-name');
        if (nameInput) nameInput.focus();
    },

    saveProfile(e) {
        e.preventDefault();
        const name = document.getElementById('profile-name').value;
        const email = document.getElementById('profile-email').value;
        const phone = document.getElementById('profile-phone').value;
        const city = document.getElementById('profile-city').value;
        const dob = document.getElementById('profile-dob').value;
        const gender = document.getElementById('profile-gender').value;

        if (Store.state.currentUser) {
            Store.state.currentUser = {
                ...Store.state.currentUser,
                name, email, phone, city, dob, gender
            };
            localStorage.setItem('medicap_user', JSON.stringify(Store.state.currentUser));
            Store.updateAuthUI();
        }

        Components.showToast('success', 'Saved', 'Your profile has been updated successfully.');
    }
};

// ========== BOOT ==========
document.addEventListener('DOMContentLoaded', () => {
    App.init();
});

/* ============================================
   MediCap — State Management Store
   ============================================ */

const Store = {
    // Current state
    state: {
        currentPage: 'home',
        currentUser: null,
        isAuthenticated: false,
        theme: 'light',
        doctors: [],
        appointments: [],
        records: [],
        filters: {
            specialty: 'All',
            city: 'All',
            search: ''
        }
    },

    // Initialize store from localStorage
    init() {
        seedDatabase();

        // Load theme
        const savedTheme = localStorage.getItem('medicap_theme') || 'light';
        this.state.theme = savedTheme;
        document.documentElement.setAttribute('data-theme', savedTheme);

        // Load user
        const savedUser = localStorage.getItem('medicap_user');
        if (savedUser) {
            this.state.currentUser = JSON.parse(savedUser);
            this.state.isAuthenticated = true;
        }

        // Load data
        this.state.doctors = JSON.parse(localStorage.getItem('medicap_doctors') || '[]');
        this.state.appointments = JSON.parse(localStorage.getItem('medicap_appointments') || '[]');
        this.state.records = JSON.parse(localStorage.getItem('medicap_records') || '[]');
    },

    // Theme management
    toggleTheme() {
        this.state.theme = this.state.theme === 'light' ? 'dark' : 'light';
        document.documentElement.setAttribute('data-theme', this.state.theme);
        localStorage.setItem('medicap_theme', this.state.theme);
        this.updateThemeIcon();
    },

    updateThemeIcon() {
        const btn = document.getElementById('theme-toggle');
        if (btn) {
            const icon = btn.querySelector('.material-icons-round');
            icon.textContent = this.state.theme === 'dark' ? 'light_mode' : 'dark_mode';
        }
    },

    // Auth management
    login(userData) {
        this.state.currentUser = userData;
        this.state.isAuthenticated = true;
        localStorage.setItem('medicap_user', JSON.stringify(userData));
        this.updateAuthUI();
    },

    logout() {
        this.state.currentUser = null;
        this.state.isAuthenticated = false;
        localStorage.removeItem('medicap_user');
        this.updateAuthUI();
    },

    updateAuthUI() {
        const loginBtn = document.getElementById('nav-login-btn');
        const userMenu = document.getElementById('user-menu');
        const displayName = document.getElementById('user-display-name');
        const mobileLoginBtn = document.getElementById('mobile-login-btn');

        if (this.state.isAuthenticated && this.state.currentUser) {
            loginBtn?.classList.add('hidden');
            userMenu?.classList.remove('hidden');
            if (displayName) {
                displayName.textContent = this.state.currentUser.name || 'User';
            }
            if (mobileLoginBtn) {
                mobileLoginBtn.textContent = 'Dashboard';
                mobileLoginBtn.setAttribute('data-page', 'dashboard');
            }
        } else {
            loginBtn?.classList.remove('hidden');
            userMenu?.classList.add('hidden');
            if (mobileLoginBtn) {
                mobileLoginBtn.textContent = 'Login / Register';
                mobileLoginBtn.setAttribute('data-page', 'login');
            }
        }
    },

    // Doctor helpers
    getDoctors(filters = {}) {
        let docs = [...this.state.doctors];

        if (filters.specialty && filters.specialty !== 'All') {
            docs = docs.filter(d => d.specialty === filters.specialty);
        }
        if (filters.city && filters.city !== 'All') {
            docs = docs.filter(d => d.city === filters.city);
        }
        if (filters.search) {
            const q = filters.search.toLowerCase();
            docs = docs.filter(d =>
                d.name.toLowerCase().includes(q) ||
                d.specialty.toLowerCase().includes(q) ||
                d.hospital.toLowerCase().includes(q)
            );
        }
        return docs;
    },

    getDoctorById(id) {
        return this.state.doctors.find(d => d.id === id);
    },

    // Appointment helpers
    getAppointments() {
        return [...this.state.appointments].sort((a, b) => new Date(b.date) - new Date(a.date));
    },

    addAppointment(appointment) {
        appointment.id = 'apt-' + Date.now().toString(36);
        this.state.appointments.push(appointment);
        localStorage.setItem('medicap_appointments', JSON.stringify(this.state.appointments));
        return appointment;
    },

    updateAppointmentStatus(id, status) {
        const apt = this.state.appointments.find(a => a.id === id);
        if (apt) {
            apt.status = status;
            localStorage.setItem('medicap_appointments', JSON.stringify(this.state.appointments));
        }
    },

    cancelAppointment(id) {
        this.updateAppointmentStatus(id, 'cancelled');
    },

    // Records helpers
    getRecords() {
        return [...this.state.records].sort((a, b) => new Date(b.date) - new Date(a.date));
    },

    addRecord(record) {
        record.id = 'rec-' + Date.now().toString(36);
        this.state.records.push(record);
        localStorage.setItem('medicap_records', JSON.stringify(this.state.records));
        return record;
    },

    // Navigation
    setPage(page) {
        this.state.currentPage = page;
        window.scrollTo({ top: 0, behavior: 'smooth' });
    },

    // Stats
    getStats() {
        const now = new Date();
        const upcoming = this.state.appointments.filter(a =>
            new Date(a.date) >= now && a.status !== 'cancelled'
        ).length;
        const completed = this.state.appointments.filter(a => a.status === 'completed').length;

        return {
            totalDoctors: this.state.doctors.length,
            totalAppointments: this.state.appointments.length,
            upcomingAppointments: upcoming,
            completedAppointments: completed,
            totalRecords: this.state.records.length,
            citiesServed: [...new Set(this.state.doctors.map(d => d.city))].length
        };
    }
};

/* ============================================
   MediCap — Main Application Controller
   v2.0 — Role-based Auth (Patient/Doctor/Admin)
   ============================================ */

const App = {
  _bookingDoctorId: null,
  _filterDebounce: null,

  // Initialize application
  async init() {
    await Store.init();
    Store.updateThemeIcon();
    Store.updateAuthUI();
    this.bindNavigation();
    this.bindTheme();
    this.bindMobileNav();
    this.bindScroll();

    // If admin, load admin data
    if (Store.state.isAuthenticated && Store.state.currentUser?.role === 'admin') {
      await Store.fetchAdminUsers();
    }

    this.renderPage('home');
    this.hidePreloader();
  },

  hidePreloader() {
    setTimeout(() => {
      const preloader = document.getElementById('preloader');
      if (preloader) preloader.classList.add('hidden');
    }, 800);
  },

  // ========== NAVIGATION ==========
  bindNavigation() {
    document.querySelectorAll('[data-page]').forEach((link) => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        const page = link.getAttribute('data-page');
        this.navigateTo(page);
      });
    });

    const avatarBtn = document.getElementById('user-avatar-btn');
    const dropdown = document.getElementById('user-dropdown');
    if (avatarBtn && dropdown) {
      avatarBtn.addEventListener('click', () => dropdown.classList.toggle('hidden'));
      document.addEventListener('click', (e) => {
        if (!avatarBtn.contains(e.target) && !dropdown.contains(e.target)) {
          dropdown.classList.add('hidden');
        }
      });
    }

    const logoutBtn = document.getElementById('logout-btn');
    if (logoutBtn) {
      logoutBtn.addEventListener('click', (e) => {
        e.preventDefault();
        this.handleLogout();
      });
    }
  },

  bindTheme() {
    const themeBtn = document.getElementById('theme-toggle');
    if (themeBtn) themeBtn.addEventListener('click', () => Store.toggleTheme());
  },

  bindMobileNav() {
    const hamburger = document.getElementById('hamburger');
    const mobileNav = document.getElementById('mobile-nav');
    const mobileOverlay = document.getElementById('mobile-overlay');
    const mobileClose = document.getElementById('mobile-close');

    const openMobile = () => {
      mobileNav.classList.remove('hidden');
      mobileOverlay.classList.remove('hidden');
      document.body.style.overflow = 'hidden';
    };
    const closeMobile = () => {
      mobileNav.classList.add('hidden');
      mobileOverlay.classList.add('hidden');
      document.body.style.overflow = '';
    };

    hamburger?.addEventListener('click', openMobile);
    mobileClose?.addEventListener('click', closeMobile);
    mobileOverlay?.addEventListener('click', closeMobile);

    document.querySelectorAll('.mobile-link, #mobile-login-btn').forEach((link) => {
      link.addEventListener('click', (e) => {
        e.preventDefault();
        closeMobile();
        this.navigateTo(link.getAttribute('data-page'));
      });
    });
  },

  bindScroll() {
    window.addEventListener('scroll', () => {
      const nav = document.getElementById('main-nav');
      nav.classList.toggle('scrolled', window.scrollY > 50);
    });
  },

  navigateTo(page, doctorId = null, city = null) {
    // Guard protected pages
    const protectedPages = ['appointments', 'records', 'dashboard', 'profile'];
    if (protectedPages.includes(page) && !Store.state.isAuthenticated) {
      Components.showToast('warning', 'Login Required', 'Please login to access this page.');
      page = 'login';
    }

    document.querySelectorAll('.nav-link').forEach((l) => l.classList.remove('active'));
    document.querySelectorAll('.mobile-link').forEach((l) => l.classList.remove('active'));

    const navPage = page === 'book-appointment' ? 'appointments' : page;
    document.querySelectorAll(`[data-page="${navPage}"]`).forEach((l) => l.classList.add('active'));

    const dropdown = document.getElementById('user-dropdown');
    if (dropdown) dropdown.classList.add('hidden');

    if (page === 'book-appointment' && doctorId) {
      this._bookingDoctorId = doctorId;
      this.renderPage('book-appointment', doctorId);
    } else if (page === 'doctors' && city) {
      Store.state.filters.city = city;
      this.renderPage('doctors');
    } else {
      Store.state.filters = { specialty: 'All', city: 'All', search: '' };
      this.renderPage(page);
    }

    Store.setPage(page);
  },

  renderPage(page, arg = null) {
    const content = document.getElementById('app-content');
    const footer = document.getElementById('main-footer');

    footer.style.display = page === 'login' || page === 'register' ? 'none' : '';

    switch (page) {
      case 'home':
        content.innerHTML = Pages.home();
        break;
      case 'doctors':
        content.innerHTML = Pages.doctors(Store.state.filters);
        break;
      case 'appointments':
        content.innerHTML = Pages.appointments();
        break;
      case 'book-appointment':
        content.innerHTML = Pages.bookAppointment(arg);
        this.bindBookingDateListener();
        break;
      case 'records':
        content.innerHTML = Pages.records();
        break;
      case 'dashboard':
        content.innerHTML = Pages.dashboard();
        break;
      case 'login':
        content.innerHTML = Pages.login();
        break;
      case 'register':
        content.innerHTML = Pages.register();
        break;
      case 'profile':
        content.innerHTML = Pages.profile();
        break;
      default:
        content.innerHTML = Pages.home();
    }

    this.triggerAnimations();
  },

  triggerAnimations() {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.style.animationPlayState = 'running';
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.1 },
    );
    document
      .querySelectorAll('.fade-in, .slide-up, .scale-in')
      .forEach((el) => observer.observe(el));
  },

  // ========== DOCTOR FILTERS ==========
  filterDoctors(type, value) {
    Store.state.filters[type] = value;
    if (type === 'search') {
      clearTimeout(this._filterDebounce);
      this._filterDebounce = setTimeout(() => this.renderPage('doctors'), 300);
    } else {
      this.renderPage('doctors');
    }
  },

  // ========== APPOINTMENTS ==========
  switchAppointmentTab(tab, btn) {
    document.querySelectorAll('.tab').forEach((t) => t.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('appointments-upcoming').classList.toggle('hidden', tab !== 'upcoming');
    document.getElementById('appointments-past').classList.toggle('hidden', tab !== 'past');
  },

  cancelAppointment(id) {
    Components.showModal(
      'Cancel Appointment',
