// ==================== MIDDLEWARE ====================
app.use(cors());
app.use(compression()); // EFFICIENCY: Gzip compression to improve performance

app.use(
  helmet({
    contentSecurityPolicy: {
      directives: {
        defaultSrc: ["'self'"],
